+import React from 'react';
+import './CharacterVisuals.css';
+
+// Icons as SVG for Reviewing state
+const MagnifyingGlassIcon = () => (
+  <svg
+    className="magnifying-glass"
+    xmlns="http://www.w3.org/2000/svg"
+    viewBox="0 0 24 24"
+    fill="none"
+    stroke="currentColor"
+    strokeWidth="2"
+    strokeLinecap="round"
+    strokeLinejoin="round"
+    width="24"
+    height="24"
+  >
+    <circle cx="11" cy="11" r="8" />
+    <line x1="21" y1="21" x2="16.65" y2="16.65" />
+  </svg>
+);
+
+const CharacterVisuals = ({ status, children }) => {
+  // Wrapper class for overlay effect
+  let effectClass = '';
+  let overlay = null;
+
+  switch (status) {
+    case 'Idle':
+      effectClass = 'glow-effect';
+      break;
+    case 'Working':
+      effectClass = 'sparkles-effect';
+      break;
+    case 'Reviewing':
+      effectClass = 'reviewing-effect';
+      overlay = <MagnifyingGlassIcon />;
+      break;
+    case 'Stalled':
+      effectClass = 'pulse-red-effect';
+      break;
+    case 'Cancelled':
+      effectClass = 'gray-overlay-effect';
+      break;
+    default:
+      break;
+  }
+
+  return (
+    <div className={`character-visuals-wrapper ${effectClass}`}>
+      {children}
+      {overlay && <div className="overlay-icon">{overlay}</div>}
+    </div>
+  );
+};
+
+export default CharacterVisuals;
