+.character-visuals-wrapper {
+  position: relative;
+  display: inline-block;
+}
+
+/* Idle: subtle glow */
+.glow-effect {
+  box-shadow: 0 0 8px 2px rgba(100, 150, 255, 0.6);
+  transition: box-shadow 0.3s ease-in-out;
+}
+
+/* Working: golden sparkles */
+.sparkles-effect {
+  position: relative;
+  animation: sparkles 1.5s infinite;
+}
+
+@keyframes sparkles {
+  0%, 100% {
+    box-shadow:
+      0 0 3px 2px gold,
+      5px 5px 5px 0px gold,
+      -5px -5px 5px 0px gold;
+  }
+  50% {
+    box-shadow:
+      0 0 6px 3px gold,
+      5px 5px 10px 2px gold,
+      -5px -5px 10px 2px gold;
+  }
+}
+
+/* Reviewing: magnifying glass overlay */
+.reviewing-effect {
+  /* no special effect on container */
+}
+.overlay-icon {
+  position: absolute;
+  top: 4px;
+  right: 4px;
+  color: #444;
+  pointer-events: none;
+}
+
+/* Stalled: red pulse */
+.pulse-red-effect {
+  animation: pulse-red 2s infinite;
+  box-shadow: 0 0 10px 3px rgba(255, 0, 0, 0.7);
+}
+
+@keyframes pulse-red {
+  0%, 100% {
+    box-shadow: 0 0 10px 3px rgba(255, 0, 0, 0.7);
+  }
+  50% {
+    box-shadow: 0 0 20px 6px rgba(255, 0, 0, 0.4);
+  }
+}
+
+/* Cancelled: gray overlay */
+.gray-overlay-effect {
+  filter: grayscale(100%);
+  opacity: 0.6;
+}
